/**
 * AudioWorklet processor for real-time audio capture.
 * Captures chunks, calculates RMS for VAD, sends to main thread.
 */
class AudioChunkProcessor extends AudioWorkletProcessor {
  constructor() {
    super();
    this.bufferSize = 4096;
    this.buffer = new Float32Array(this.bufferSize);
    this.bufferIndex = 0;
  }

  process(inputs) {
    const input = inputs[0]?.[0];
    if (!input) return true;

    for (let i = 0; i < input.length; i++) {
      this.buffer[this.bufferIndex++] = input[i];

      if (this.bufferIndex >= this.bufferSize) {
        let sum = 0;
        for (let j = 0; j < this.bufferSize; j++) {
          sum += this.buffer[j] * this.buffer[j];
        }
        const rms = Math.sqrt(sum / this.bufferSize);

        // Float32 to Int16 (50% size reduction)

    const rms = Math.sqrt(sum / this.bufferSize);

        // Float32 to Int16 (50% size reduction)
        const int16 = new Int16Array(this.bufferSize);
        for (let j = 0; j < this.bufferSize; j++) {
          int16[j] = Math.max(-32768, Math.min(32767,
            Math.floor(this.buffer[j] * 32768)));
        }

        this.port.postMessage({ audioData: int16.buffer, rms }, [int16.buffer]);
        this.buffer = new Float32Array(this.bufferSize);
        this.bufferIndex = 0;
      }
    }
    return true;
  }
}

